import React, { useEffect, useState } from "react";
import socket from "../socket";

function Host() {
  const [gamePin, setGamePin] = useState("");
  const [players, setPlayers] = useState([]);
  const [leaderboard, setLeaderboard] = useState([]);
  const [question, setQuestion] = useState("");
  const [options, setOptions] = useState(["", "", "", ""]);
  const [correctAnswer, setCorrectAnswer] = useState("");

  useEffect(() => {
    socket.on("gameCreated", (pin) => {
      setGamePin(pin);
    });

    socket.on("playersUpdated", (data) => {
      setPlayers(data || []);
    });

    socket.on("leaderboardUpdated", (data) => {
      setLeaderboard(data || []);
    });

    return () => {
      socket.off("gameCreated");
      socket.off("playersUpdated");
      socket.off("leaderboardUpdated");
    };
  }, []);

  const createGame = () => {
    socket.emit("createGame");
  };

  const sendQuestion = () => {
    if (!gamePin) {
      alert("Please create game first");
      return;
    }

    if (!question || !correctAnswer) {
      alert("Please enter question and correct answer");
      return;
    }

    socket.emit("sendQuestion", {
      gamePin,
      question,
      options,
      correctAnswer,
    });

    alert("Question sent to players");
  };

  return (
    <div style={{ padding: "30px", fontFamily: "Arial" }}>
      <h1>Host Dashboard</h1>

      <button onClick={createGame}>Create Game</button>

      {gamePin && (
        <h2>
          Game PIN: <span style={{ color: "green" }}>{gamePin}</span>
        </h2>
      )}

      <hr />

      <h2>Create Question</h2>

      <input
        type="text"
        placeholder="Enter question"
        value={question}
        onChange={(e) => setQuestion(e.target.value)}
        style={{ width: "100%", padding: "10px", marginBottom: "10px" }}
      />

      {options.map((option, index) => (
        <input
          key={index}
          type="text"
          placeholder={`Option ${index + 1}`}
          value={option}
          onChange={(e) => {
            const newOptions = [...options];
            newOptions[index] = e.target.value;
            setOptions(newOptions);
          }}
          style={{ width: "100%", padding: "10px", marginBottom: "10px" }}
        />
      ))}

      <input
        type="text"
        placeholder="Correct answer"
        value={correctAnswer}
        onChange={(e) => setCorrectAnswer(e.target.value)}
        style={{ width: "100%", padding: "10px", marginBottom: "10px" }}
      />

      <button onClick={sendQuestion}>Send Question</button>

      <hr />

      <h2>Joined Players</h2>

      {(players || []).length === 0 ? (
        <p>No players joined yet</p>
      ) : (
        (players || []).map((player, index) => (
          <p key={index}>
            {index + 1}. {player.name || player}
          </p>
        ))
      )}

      <hr />

      <h2>Leaderboard</h2>

      {(leaderboard || []).length === 0 ? (
        <p>No scores yet</p>
      ) : (
        (leaderboard || []).map((player, index) => (
          <p key={index}>
            {index + 1}. {player.name || player.playerName || "Player"} -{" "}
            {player.score || 0}
          </p>
        ))
      )}
    </div>
  );
}

export default Host;
